const pad = n => String(n).padStart(2, '0');
const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

const hoy                  = new Date();
const primerDiaMesActual   = new Date(hoy.getFullYear(), hoy.getMonth(), 1);
const ultimoDiaMesAnterior = new Date(primerDiaMesActual - 1);
const primerDiaMesAnterior = new Date(ultimoDiaMesAnterior.getFullYear(), ultimoDiaMesAnterior.getMonth(), 1);

const anio = String(ultimoDiaMesAnterior.getFullYear());
const mes  = pad(ultimoDiaMesAnterior.getMonth() + 1);

const config = $('Configuración').first().json;
const folderPath = `${config.ONEDRIVE_BASE_PATH}/${anio}/${mes}`;

return [{ json: {
  ONEDRIVE_FOLDER_PATH: folderPath,
  EMAIL_FROM:           config.EMAIL_FROM,
  EMAIL_RECIPIENTS:     config.EMAIL_RECIPIENTS,
  fechaInicio:  fmt(primerDiaMesAnterior),
  fechaFin:     fmt(ultimoDiaMesAnterior),
  anio, mes,
  nombreTxt:   `RES2175_T3_ECOPETROL_${anio}_${mes}.txt`,
  nombreExcel: `RES2175_T3_ECOPETROL_${anio}_${mes}.xlsx`
}}];

const MAX = 1_000_000;
const items = $input.all();
const total = items.length;

if (total === 0) throw new Error('Sin registros para el período. Verificar filtros.');
if (total > MAX) throw new Error(`Límite superado: ${total.toLocaleString()} registros (máx ${MAX.toLocaleString()}).`);

const meta = $('Calcular Rango Mes Vencido').first().json;
console.log(`Registros válidos: ${total}`);

return items.map(item => ({ json: { ...item.json, _meta: { ...meta, totalRegistros: total } } }));

const XLSX = require('xlsx');

const MAX_FILAS_POR_HOJA = 900_000;
const items = $input.all();
const meta  = items[0].json._meta;

const COLS_PLANO = [
  'TipoRegistro','Consecutivo','TipoIdentificacion','NumeroIdentificacion',
  'FechaNacimiento','Sexo','CodigoPertenenciaEtnica',
  'PrimerApellido','SegundoApellido','PrimerNombre','SegundoNombre',
  'FechaAtencion','FinalidadConsulta','CodigoCUPS','PesoKg','TallaCm','FechaTomHemoglobina'
];

const HEADERS_EXCEL = {
  TipoRegistro:'Tipo Registro', Consecutivo:'Consecutivo',
  TipoIdentificacion:'Tipo ID', NumeroIdentificacion:'Número ID',
  FechaNacimiento:'Fecha Nacimiento', Sexo:'Sexo',
  CodigoPertenenciaEtnica:'Pertenencia Étnica',
  PrimerApellido:'Primer Apellido', SegundoApellido:'Segundo Apellido',
  PrimerNombre:'Primer Nombre', SegundoNombre:'Segundo Nombre',
  FechaAtencion:'Fecha Atención', FinalidadConsulta:'Finalidad Consulta',
  CodigoCUPS:'Código CUPS', PesoKg:'Peso (kg)', TallaCm:'Talla (cm)',
  FechaTomHemoglobina:'Fecha Hemoglobina'
};

// ── 1. TXT ──────────────────────────────────────────────────
const txt    = items.map(i => COLS_PLANO.map(c => i.json[c] ?? '').join('|')).join('\n');
const txt_b64 = Buffer.from(txt, 'utf-8').toString('base64');
console.log(`TXT: ${items.length} registros`);

// ── 2. Excel ────────────────────────────────────────────────
const wb = XLSX.utils.book_new();
const totalSheets = Math.ceil(items.length / MAX_FILAS_POR_HOJA);

for (let s = 0; s < totalSheets; s++) {
  const chunk = items.slice(s * MAX_FILAS_POR_HOJA, (s + 1) * MAX_FILAS_POR_HOJA);
  const datos = chunk.map(i => {
    const row = {};
    COLS_PLANO.forEach(col => { row[HEADERS_EXCEL[col]] = i.json[col] ?? ''; });
    return row;
  });
  const ws = XLSX.utils.json_to_sheet(datos);
  ws['!cols'] = Object.values(HEADERS_EXCEL).map(h => ({ wch: Math.max(h.length, 12) }));
  XLSX.utils.book_append_sheet(wb, ws, totalSheets > 1 ? `Datos ${s+1} de ${totalSheets}` : 'Datos');
}

// Hoja resumen
const resumen = XLSX.utils.aoa_to_sheet([
  ['Reporte Resolución 2175 de 2015 — Registro Tipo 3 (0 a 5 años)'], [],
  ['Período',         `${meta.fechaInicio} al ${meta.fechaFin}`],
  ['Total registros',  items.length.toLocaleString()],
  ['Hojas de datos',   totalSheets],
  ['Contrato',         'Unidad Móvil Ecopetrol (168)'],
  ['Archivo plano',    meta.nombreTxt],
  ['Generado',         new Date().toLocaleString('es-CO')]
]);
XLSX.utils.book_append_sheet(wb, resumen, 'Resumen');

const excel_b64 = XLSX.write(wb, { type: 'base64', bookType: 'xlsx' });
console.log(`Excel: ${totalSheets} hoja(s) de datos + resumen`);

// ── Salida: 1 item con 2 campos binarios ────────────────────
return [{
  json: {
    nombreTxt:            meta.nombreTxt,
    nombreExcel:          meta.nombreExcel,
    fechaInicio:          meta.fechaInicio,
    fechaFin:             meta.fechaFin,
    totalRegistros:       meta.totalRegistros,
    totalHojasExcel:      totalSheets,
    ONEDRIVE_FOLDER_PATH: meta.ONEDRIVE_FOLDER_PATH,
    EMAIL_FROM:           meta.EMAIL_FROM,
    EMAIL_RECIPIENTS:     meta.EMAIL_RECIPIENTS
  },
  binary: {
    archivo_txt: {
      data:     txt_b64,
      mimeType: 'text/plain',
      fileName: meta.nombreTxt
    },
    archivo_excel: {
      data:     excel_b64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: meta.nombreExcel
    }
  }
}];

// Une los links de ambas ramas con los metadatos del archivo
const item  = $input.first().json;
const meta  = $('Generar TXT y Excel').first().json;

return [{ json: {
  linkTxt:          item.linkTxt,
  linkExcel:        item.linkExcel,
  nombreTxt:        meta.nombreTxt,
  nombreExcel:      meta.nombreExcel,
  fechaInicio:      meta.fechaInicio,
  fechaFin:         meta.fechaFin,
  totalRegistros:   meta.totalRegistros,
  totalHojasExcel:  meta.totalHojasExcel,
  rutaOneDrive:     meta.ONEDRIVE_FOLDER_PATH,
  EMAIL_FROM:       meta.EMAIL_FROM,
  EMAIL_RECIPIENTS: meta.EMAIL_RECIPIENTS
}}];
